import{_ as t,C as r,o as s,c as i,ai as e,E as l,w as n,a as c}from"./chunks/framework.BH_J6TYN.js";const f=JSON.parse('{"title":"Variantes de productos","description":"Tallas, colores y opciones para tus productos","frontmatter":{"title":"Variantes de productos","description":"Tallas, colores y opciones para tus productos"},"headers":[],"relativePath":"cat/variantes.md","filePath":"cat/variantes.md"}'),p={name:"cat/variantes.md"};function d(u,a,m,g,h,_){const o=r("Note");return s(),i("div",null,[a[1]||(a[1]=e('<p>Las variantes permiten que un mismo producto tenga diferentes opciones que el cliente elige antes de agregar al carrito.</p><h2 id="tipos-de-variantes" tabindex="-1">Tipos de variantes <a class="header-anchor" href="#tipos-de-variantes" aria-label="Permalink to &quot;Tipos de variantes&quot;">​</a></h2><p><strong>Talla</strong> → S, M, L, XL, XXL (ideal para ropa y calzado)</p><p><strong>Color</strong> → con selector visual de colores</p><p><strong>Talla y color</strong> → combina ambas opciones</p><p><strong>Extras/opciones</strong> → opciones personalizadas como materiales o características (plan Anual)</p><h2 id="como-configurar-variantes" tabindex="-1">Cómo configurar variantes <a class="header-anchor" href="#como-configurar-variantes" aria-label="Permalink to &quot;Cómo configurar variantes&quot;">​</a></h2><ol><li>Tu panel → <strong>Qué Vendes</strong></li><li>Abre el producto</li><li>Ve a la sección <strong>Variantes</strong></li><li>Selecciona el tipo: talla, color, talla+color, o extras</li><li>Agrega las opciones disponibles</li><li>Guarda</li></ol><h2 id="ejemplo-practico-para-ropa" tabindex="-1">Ejemplo práctico para ropa <a class="header-anchor" href="#ejemplo-practico-para-ropa" aria-label="Permalink to &quot;Ejemplo práctico para ropa&quot;">​</a></h2><p>Producto: <strong>Camisa polo básica</strong></p><p>Variante tipo <strong>Talla y color</strong>:</p><p>Tallas: S · M · L · XL Colores: Blanco · Negro · Azul marino · Rojo</p><p>Cuando el cliente quiere esa camisa, primero elige la talla y el color. En el mensaje de WhatsApp llega: &quot;1x Camisa polo básica (Talla M - Color Azul marino)&quot;.</p><h2 id="variantes-sin-stock" tabindex="-1">Variantes sin stock <a class="header-anchor" href="#variantes-sin-stock" aria-label="Permalink to &quot;Variantes sin stock&quot;">​</a></h2><p>Si una talla o color específico se agotó, puedes desactivar solo esa variante sin desactivar todo el producto.</p>',15)),l(o,null,{default:n(()=>[...a[0]||(a[0]=[c(" Las variantes básicas (talla y color) están disponibles desde el plan Semestral. Las variantes de extras y opciones personalizadas son exclusivas del plan Anual. ",-1)])]),_:1}),a[2]||(a[2]=e('<h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/cat/catalogo-productos.html">Catálogo de productos</a> — Gestión completa de productos</li><li><a href="/cat/carrito-whatsapp.html">Carrito y WhatsApp</a> — Las variantes se incluyen en el mensaje del carrito</li><li><a href="/cat/que-es-synticat.html">¿Qué es SYNTIcat?</a> — Planes y funcionalidades</li></ul>',2))])}const T=t(p,[["render",d]]);export{f as __pageData,T as default};
